import{_ as e,o as d,c as a,ag as o}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Aliases Padrão: Atalhos Essenciais de Shell | Dotfiles (PT)","titleTemplate":":title","description":"Aliases de shell essenciais para navegação, controle do sistema e tarefas diarias. Simplifique seu fluxo de trabalho no terminal com estes atalhos universais.","frontmatter":{"title":"Aliases Padrão: Atalhos Essenciais de Shell","description":"Aliases de shell essenciais para navegação, controle do sistema e tarefas diarias. Simplifique seu fluxo de trabalho no terminal com estes atalhos universais.","lang":"pt-BR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliases Padrão: Atalhos Essenciais de Shell preview","canonical":"/pt/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliases Padrão: Atalhos Essenciais de Shell","pageType":"docs","schemaType":"WebPage","metaTitle":"Aliases Padrão | Dotfiles","permalink":"/pt/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"aliases padrão, aliases shell, atalhos terminal, dotfiles, aliases bash"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Aliases Padrão | Dotfiles"},{"name":"twitter:description","content":"Aliases de shell essenciais para navegação, controle do sistema e tarefas diarias."},{"name":"og:title","content":"Aliases Padrão | Dotfiles"},{"name":"og:description","content":"Aliases de shell essenciais para navegação, controle do sistema e tarefas diarias."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"pt_BR"}]},"headers":[],"relativePath":"pt/aliases/default/index.md","filePath":"pt/aliases/default/index.md","lastUpdated":1773010926000}'),s={name:"pt/aliases/default/index.md"};function i(r,t,l,c,n,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="aliases-padrao" tabindex="-1">Aliases Padrão <a class="header-anchor" href="#aliases-padrao" aria-label="Permalink to &quot;Aliases Padrão&quot;">​</a></h1><p>Atalhos de shell essenciais para tarefas diarias do terminal.</p><h2 id="visao-geral" tabindex="-1">Visão Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visão Geral&quot;">​</a></h2><p>Os aliases padrão fornecem uma colecao de atalhos de shell universais que simplificam operações comuns do terminal. Estes aliases são definidos em <code>default.aliases.sh</code> e são carregados automaticamente pelo chezmoi em todos os shells suportados.</p><p>Estes atalhos cobrem utilitarios gerais, comandos de saida, diagnosticos de rede, monitoramento do sistema e navegação do sistema de arquivos.</p><h2 id="referencia" tabindex="-1">Referência <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referência&quot;">​</a></h2><h3 id="geral" tabindex="-1">Geral <a class="header-anchor" href="#geral" aria-label="Permalink to &quot;Geral&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>Exibir data e hora atuais</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>Imprimir diretorio de trabalho</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>Exibir variavel PATH em novas linhas</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>Recarregar o shell</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>Acompanhar saida de arquivo em tempo real</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>Mostrar numero da semana atual</td></tr></tbody></table><h3 id="saida-e-desligamento" tabindex="-1">Saida e Desligamento <a class="header-anchor" href="#saida-e-desligamento" aria-label="Permalink to &quot;Saida e Desligamento&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>Sair do shell</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>Sair do shell</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>Sair do shell</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>Sair do shell (estilo vim)</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>Parar o sistema</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>Desligar o sistema</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>Reiniciar o sistema</td></tr></tbody></table><h3 id="historico" tabindex="-1">Historico <a class="header-anchor" href="#historico" aria-label="Permalink to &quot;Historico&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>Ver historico de comandos</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>Mostrar historico com timestamps ISO 8601</td></tr></tbody></table><h3 id="rede" tabindex="-1">Rede <a class="header-anchor" href="#rede" aria-label="Permalink to &quot;Rede&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>Configurar interfaces de rede</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>Obter parametros de rede para en0</td></tr><tr><td><code>nls</code></td><td><code>sudo lsof -i -P | grep LISTEN</code></td><td>Mostrar ouvintes de rede ativos</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>Listar portas abertas</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>Ping com limite de 5 pacotes</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>Listar todas as portas em escuta</td></tr></tbody></table><h3 id="monitoramento-do-sistema" tabindex="-1">Monitoramento do Sistema <a class="header-anchor" href="#monitoramento-do-sistema" aria-label="Permalink to &quot;Monitoramento do Sistema&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>Monitor de processos interativo</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>Limpar arquivos de log ASL</td></tr></tbody></table><h3 id="utilitarios" tabindex="-1">Utilitarios <a class="header-anchor" href="#utilitarios" aria-label="Permalink to &quot;Utilitarios&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrição</th></tr></thead><tbody><tr><td><code>ctf</code></td><td><code>ls -1 | wc -l</code></td><td>Contar arquivos no diretorio atual</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>Busca rapida de arquivos</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>Recarregar o shell</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>Obter clima atual</td></tr></tbody></table>',18)])])}const p=e(s,[["render",i]]);export{u as __pageData,p as default};
